1	export type Item = { type: string; material?: string; enchantment?: number; cursed?: boolean };
2	export type Damage = { itemType: string; amount: number };
3	export type QuoteStep = { op: "quote"; items: Item[] };
4	export type ClaimStep = { op: "claim"; policy: number; incident: { cause: string; damages: Damage[] } };
5	export type Step = QuoteStep | ClaimStep;
6	export type Result = { premium: number } | { payout: number };
7	
8	const DEDUCTIBLE = 100;
9	
10	const PROCESSING_FEE = 5;
11	const FIRST_INSURANCE_RATE = 0.1;
12	const CURSE_RATE = 0.5;
13	const HIGH_ENCHANTMENT_THRESHOLD = 5;
14	const HIGH_ENCHANTMENT_RATE = 0.3;
15	
16	const BASE_PREMIUM_BY_TYPE: Record<string, number> = {
17	  sword: 100,
18	  amulet: 60,
19	  staff: 80,
20	  potion: 40,
21	  rune: 25,
22	  moonstone: 25,
23	};
24	
25	const isKnownItemType = (item: Item): boolean => item.type in BASE_PREMIUM_BY_TYPE;
26	
27	const basePremiumFor = (item: Item): number => BASE_PREMIUM_BY_TYPE[item.type] ?? 0;
28	
29	const assertKnownItemTypes = (items: Item[]): void => {
30	  for (const item of items) {
31	    if (!isKnownItemType(item)) {
32	      throw new Error(`Unknown item type: ${item.type}`);
33	    }
34	  }
35	};
36	
37	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
38	const COMPONENT_BLOCK_SIZE = 3;
39	const COMPONENT_BLOCK_PRICE = 60;
40	const COMPONENT_UNIT_PRICE = 25;
41	
42	const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);
43	
44	const roundPremium = (amount: number): number => Math.ceil(amount);
45	
46	const priceForComponentCount = (count: number): number =>
47	  count === COMPONENT_BLOCK_SIZE ? COMPONENT_BLOCK_PRICE : count * COMPONENT_UNIT_PRICE;
48	
49	const sumComponentBase = (componentCountsByType: Map<string, number>): number => {
50	  let total = 0;
51	  for (const count of componentCountsByType.values()) {
52	    total += priceForComponentCount(count);
53	  }
54	  return total;
55	};
56	
57	const baseForItems = (items: Item[]): number => {
58	  const componentCountsByType = new Map<string, number>();
59	  let nonComponentBase = 0;
60	  for (const item of items) {
61	    if (isComponent(item)) {
62	      componentCountsByType.set(item.type, (componentCountsByType.get(item.type) ?? 0) + 1);
63	    } else {
64	      nonComponentBase += basePremiumFor(item);
65	    }
66	  }
67	  return nonComponentBase + sumComponentBase(componentCountsByType);
68	};
69	
70	const curseSurchargeFor = (item: Item): number =>
71	  item.cursed ? basePremiumFor(item) * CURSE_RATE : 0;
72	
73	const highEnchantmentSurchargeFor = (item: Item): number =>
74	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD
75	    ? basePremiumFor(item) * HIGH_ENCHANTMENT_RATE
76	    : 0;
77	
78	const PER_ITEM_MODIFIERS: ReadonlyArray<(item: Item) => number> = [
79	  curseSurchargeFor,
80	  highEnchantmentSurchargeFor,
81	];
82	
83	const modifiersForItem = (item: Item): number =>
84	  PER_ITEM_MODIFIERS.reduce((sum, modifier) => sum + modifier(item), 0);
85	
86	const itemModifiersFor = (items: Item[]): number =>
87	  items.reduce((sum, item) => sum + modifiersForItem(item), 0);
88	
89	const LOYALTY_YEARS_THRESHOLD = 2;
90	const LOYALTY_DISCOUNT_RATE = 0.2;
91	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
92	
93	type PolicyContext = { yearsWithMHPCO: number; isFollowUp: boolean };
94	type PolicyModifier = (base: number, context: PolicyContext) => number;
95	
96	const firstInsuranceSurcharge: PolicyModifier = (base) => base * FIRST_INSURANCE_RATE;
97	
98	const loyaltyDiscount: PolicyModifier = (base, { yearsWithMHPCO }) =>
99	  yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD ? -base * LOYALTY_DISCOUNT_RATE : 0;
100	
101	const followUpDiscount: PolicyModifier = (base, { isFollowUp }) =>
102	  isFollowUp ? -base * FOLLOW_UP_DISCOUNT_RATE : 0;
103	
104	const POLICY_MODIFIERS: ReadonlyArray<PolicyModifier> = [
105	  firstInsuranceSurcharge,
106	  loyaltyDiscount,
107	  followUpDiscount,
108	];
109	
110	const policyAdjustmentFor = (base: number, context: PolicyContext): number =>
111	  POLICY_MODIFIERS.reduce((sum, modifier) => sum + modifier(base, context), 0);
112	
113	const quotePremium = (items: Item[], context: PolicyContext): number => {
114	  const base = baseForItems(items);
115	  return roundPremium(base + itemModifiersFor(items) + policyAdjustmentFor(base, context) + PROCESSING_FEE);
116	};
117	
118	const FULL_REIMBURSEMENT_RATE = 1;
119	const HIGH_ENCHANTMENT_CLAIM_THRESHOLD = 8;
120	const HIGH_ENCHANTMENT_CLAIM_RATE = 0.5;
121	
122	const isHighEnchantmentForClaim = (item: Item): boolean =>
123	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_CLAIM_THRESHOLD;
124	
125	const reimbursementRateFor = (item: Item): number =>
126	  isHighEnchantmentForClaim(item) ? HIGH_ENCHANTMENT_CLAIM_RATE : FULL_REIMBURSEMENT_RATE;
127	
128	const payoutForDamage = (damage: Damage, item: Item): number =>
129	  Math.floor(damage.amount * reimbursementRateFor(item) - DEDUCTIBLE);
130	
131	const requireItemByType = (items: Item[], itemType: string): Item => {
132	  const item = items.find((candidate) => candidate.type === itemType);
133	  if (item === undefined) {
134	    throw new Error(`Item type not in policy: ${itemType}`);
135	  }
136	  return item;
137	};
138	
139	const assertNonNegativeDamage = (damage: Damage): void => {
140	  if (damage.amount < 0) {
141	    throw new Error(`Negative damage amount: ${damage.amount}`);
142	  }
143	};
144	
145	const assertDamageCountsWithinPolicy = (damages: Damage[], policyItems: Item[]): void => {
146	  const damageCounts = new Map<string, number>();
147	  for (const damage of damages) {
148	    damageCounts.set(damage.itemType, (damageCounts.get(damage.itemType) ?? 0) + 1);
149	  }
150	  for (const [itemType, count] of damageCounts) {
151	    const insuredCount = policyItems.filter((item) => item.type === itemType).length;
152	    if (count > insuredCount) {
153	      throw new Error(`More damages of type ${itemType} than policy covers`);
154	    }
155	  }
156	};
157	
158	const computePayout = (claim: ClaimStep, policyItems: Item[]): number => {
159	  assertDamageCountsWithinPolicy(claim.incident.damages, policyItems);
160	  return claim.incident.damages.reduce((sum, damage) => {
161	    assertNonNegativeDamage(damage);
162	    return sum + payoutForDamage(damage, requireItemByType(policyItems, damage.itemType));
163	  }, 0);
164	};
165	
166	type ScenarioState = {
167	  readonly yearsWithMHPCO: number;
168	  readonly policyItemsByIndex: Map<number, Item[]>;
169	  quoteCount: number;
170	};
171	
172	const handleQuote = (step: QuoteStep, index: number, state: ScenarioState): Result => {
173	  assertKnownItemTypes(step.items);
174	  state.policyItemsByIndex.set(index, step.items);
175	  const premium = quotePremium(step.items, {
176	    yearsWithMHPCO: state.yearsWithMHPCO,
177	    isFollowUp: state.quoteCount > 0,
178	  });
179	  state.quoteCount++;
180	  return { premium };
181	};
182	
183	const handleClaim = (step: ClaimStep, state: ScenarioState): Result => ({
184	  payout: computePayout(step, state.policyItemsByIndex.get(step.policy) ?? []),
185	});
186	
187	export const runScenario = (input: {
188	  customer: { yearsWithMHPCO: number };
189	  steps: Step[];
190	}): { results: Result[] } => {
191	  const state: ScenarioState = {
192	    yearsWithMHPCO: input.customer.yearsWithMHPCO,
193	    policyItemsByIndex: new Map<number, Item[]>(),
194	    quoteCount: 0,
195	  };
196	  const results: Result[] = input.steps.map((step, index) =>
197	    step.op === "quote" ? handleQuote(step, index, state) : handleClaim(step, state),
198	  );
199	  return { results };
200	};
